use std::collections::HashMap;

struct UnionFind {
    parent: Vec<i64>,
    size: Vec<i64>,
    count: i64,
}

impl UnionFind {
    fn new(n: i64) -> Self {
        let parent = (0..n).collect();
        let size = vec![1; n as usize];
        UnionFind {
            parent,
            size,
            count: n,
        }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn union(&mut self, x: i64, y: i64) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x == root_y {
            return;
        }
        if self.size[root_x as usize] < self.size[root_y as usize] {
            self.parent[root_x as usize] = root_y;
            self.size[root_y as usize] += self.size[root_x as usize];
        } else {
            self.parent[root_y as usize] = root_x;
            self.size[root_x as usize] += self.size[root_y as usize];
        }
        self.count -= 1;
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if k == 1 {
        return 0;
    }
    if n < k {
        return -1;
    }
    let mut edges = edges;
    edges.sort_by_key(|e| e[2]);
    let mut uf = UnionFind::new(n);
    let mut time_map = HashMap::new();
    for edge in &edges {
        let u = edge[0];
        let v = edge[1];
        let time = edge[2];
        time_map.entry(time).or_insert(vec![]).push((u, v));
    }
    let mut sorted_times: Vec<_> = time_map.keys().cloned().collect();
    sorted_times.sort();
    let mut left = 0;
    let mut right = sorted_times.len();
    let mut answer = 0;
    // Check if initial count is already >= k
    if uf.count >= k {
        answer = 0;
    } else {
        answer = -1;
    }
    for &t in &sorted_times {
        let edges_to_remove = time_map.get(&t).unwrap();
        for &(u, v) in edges_to_remove {
            uf.union(u, v);
        }
        if uf.count >= k {
            answer = t;
            break;
        }
    }
    if answer == 0 && uf.count < k {
        // Need to check if we can find a t beyond the last time
        if edges.is_empty() {
            if n >= k {
                return 0;
            } else {
                return -1;
            }
        }
        let max_time = edges.last().unwrap()[2];
        answer = max_time + 1;
    }
    answer
}
