            let current_time = times[i];
            if let Some(edges_at_time) = time_map.get(&current_time) {
                for &(u, v) in edges_at_time {
                    temp_uf.union(u, v);
                }
            }
        }

        if temp_uf.count >= k {
            answer = t;
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    if left < times.len() {
        answer = times[left];
    } else {
        if let Some(max_time) = edges.iter().map(|e| e[2]).max() {
            answer = max_time + 1;
        } else {
            answer = 0;
        }
    }

    // Check if the initial count is already >= k
    let mut initial_uf = UnionFind::new(n);
    if initial_uf.count >= k {
        return 0;
    }

    // Binary search between 0 and max_time + 1
    let max_time = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut low = 0;
    let mut high = max_time + 1;
    let mut result = 0;

    while low <= high {
        let mid = low + (high - low) / 2;
        let mut uf = UnionFind::new(n);

        for edge in &edges {
            if edge[2] > mid {
                uf.union(edge[0] as usize, edge[1] as usize);
            }
        }

        if uf.count >= k {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    result
}
