```rust
use std::collections::BinaryHeap;

struct UnionFind {
    parent: Vec<usize>,
    size: Vec<usize>,
    count: usize,
}

impl UnionFind {
    fn new(n: usize) -> Self {
        let parent = (0..n).collect();
        let size = vec![1; n];
        UnionFind {
            parent,
            size,
            count: n,
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x == root_y {
            return false;
        }
        if self.size[root_x] < self.size[root_y] {
            self.parent[root_x] = root_y;
            self.size[root_y] += self.size[root_x];
        } else {
            self.parent[root_y] = root_x;
            self.size[root_x] += self.size[root_y];
        }
        self.count -= 1;
        true
    }

    fn get_count(&self) -> usize {
        self.count
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut uf = UnionFind::new(n);
    let initial_components = uf.get_count();
    if initial_components >= k {
        return 0;
    }

    let mut max_heap = BinaryHeap::new();
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let time = edge[2];
        max_heap.push((time, u, v));
    }

    let mut t = 0;
    let mut edges_removed = Vec::new();
    while let Some((time, u, v)) = max_heap.pop() {
        edges_removed.push((time, u, v));
        t = time;
        let mut temp_uf = UnionFind::new(n);
        for &(t_removed, u, v) in &edges_removed {
            if t_removed <= t {
                continue;
            }
            temp_uf.union(u, v);
        }
        if temp_uf.get_count() >= k {
            return t;
        }
    }

    // If removing all edges still doesn't reach k components, find the minimal t
    let mut left = 0;
    let mut right = edges_removed.iter().map(|&(t, _, _)| t).max().unwrap_or(0);
    let mut answer = right;

    while left <= right {
        let mid = left + (right - left) / 2;
        let mut temp_uf = UnionFind::new(n);
        for &(t, u, v) in &edges_removed {
            if t <= mid {
                continue;
            }
            temp_uf.union(u, v);
        }
        if temp_uf.get_count() >= k {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    answer
}
